```class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        unordered_map<char, int> charVals;
        for (int i = 0; i < chars.size(); i++) {
            charVals[chars[i]] = vals[i];
        }
        int maxCost = 0, currCost = 0;
        for (char c : s) {
            currCost += charVals.count(c) ? charVals[c] : c - 'a' + 1;
            maxCost = max(maxCost, currCost);
            if (currCost < 0) currCost = 0;
        }
        return maxCost;
    }
};
